import React, { useState } from 'react';
import axios from 'axios';

// Receive setReport and isProcessing props from App.js
const InputForm = ({ setReport, isProcessing }) => {
    const [formData, setFormData] = useState({
        hours: '',
        attendance: '',
        marks: ''
    });

    const handleSubmit = async (e) => {
        e.preventDefault();
        
        // This connects to your FastAPI server on port 8000
        const endpoint = 'http://127.0.0.1:8000/predict'; 
        
        try {
            const response = await axios.post(endpoint, {
                hours: parseFloat(formData.hours),
                attendance: parseFloat(formData.attendance),
                marks: parseFloat(formData.marks)
            });
            
            // Pass the API response to the simulation function in App.js
            setReport(response.data);
        } catch (error) {
            console.error("Backend connection failure:", error);
            alert("API connection timed out. Verify your Python Uvicorn server is running on port 8000.");
        }
    };

    return (
        <div className="form-container">
            <form onSubmit={handleSubmit}>
                <div className="input-group">
                    <label>Daily Study Commitment</label>
                    <input 
                        type="number" 
                        placeholder="e.g. 5" 
                        value={formData.hours}
                        onChange={(e) => setFormData({...formData, hours: e.target.value})} 
                        required 
                    />
                </div>

                <div className="input-group">
                    <label>Engagement / Attendance (%)</label>
                    <input 
                        type="number" 
                        placeholder="e.g. 85" 
                        value={formData.attendance}
                        onChange={(e) => setFormData({...formData, attendance: e.target.value})} 
                        required 
                    />
                </div>

                <div className="input-group">
                    <label>Benchmark (Previous Marks %)</label>
                    <input 
                        type="number" 
                        placeholder="e.g. 70" 
                        value={formData.marks}
                        onChange={(e) => setFormData({...formData, marks: e.target.value})} 
                        required 
                    />
                </div>

                {/* Submit button dynamically changes on submission */}
                <button type="submit" disabled={isProcessing}>
                    {isProcessing ? <span className="spinner"></span> : "Analyze Performance Index"}
                </button>
            </form>
        </div>
    );
};

export default InputForm;
